import React, { useState } from 'react';
import { Bell, Menu, Moon, Sun, User } from 'lucide-react-native';
import { Link } from 'react-router-dom';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [theme, setTheme] = useState('dark');

  const handleToggle = () => {
    setIsOpen(!isOpen);
  };

  const handleThemeToggle = () => {
    setTheme(theme === 'dark' ? 'light' : 'dark');
  };

  return (
    <nav className="bg-zinc-600 text-zinc-400 py-4 md:py-6 lg:py-8 sticky top-0 z-50">
      <div className="container mx-auto flex justify-between items-center">
        <Link to="/" className="text-lg font-bold text-zinc-200">
          Vestia
        </Link>
        <button
          className="lg:hidden flex justify-center w-8 h-8 bg-zinc-700 rounded-md hover:bg-zinc-800"
          onClick={handleToggle}
        >
          <Menu size={24} color="#fff" />
        </button>
        <ul
          className={`lg:flex hidden justify-end items-center space-x-4 ${
            isOpen ? 'block' : 'hidden'
          } lg:space-x-6`}
        >
          <li>
            <Link to="/" className="text-zinc-400 hover:text-zinc-200">
              Home
            </Link>
          </li>
          <li>
            <Link to="/about" className="text-zinc-400 hover:text-zinc-200">
              About
            </Link>
          </li>
          <li>
            <Link to="/contact" className="text-zinc-400 hover:text-zinc-200">
              Contact
            </Link>
          </li>
        </ul>
        <div className="hidden lg:flex justify-end items-center space-x-4">
          <button
            className="flex justify-center w-8 h-8 bg-zinc-700 rounded-md hover:bg-zinc-800"
            onClick={handleThemeToggle}
          >
            {theme === 'dark' ? <Moon size={24} color="#fff" /> : <Sun size={24} color="#fff" />}
          </button>
          <button
            className="flex justify-center w-8 h-8 bg-zinc-700 rounded-md hover:bg-zinc-800"
          >
            <Bell size={24} color="#fff" />
          </button>
          <button
            className="flex justify-center w-8 h-8 bg-zinc-700 rounded-md hover:bg-zinc-800"
          >
            <User size={24} color="#fff" />
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

