import React, { useState, useEffect } from 'react';
import { ArrowLeft, ArrowRight } from 'lucide-react-native';
import 'react-responsive-carousel/lib/styles/carousel.min.css';

const TestimonialCarousel = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [testimonials, setTestimonials] = useState([
    {
      id: 1,
      name: 'John Doe',
      testimonial: 'Vestia has been a game-changer for my shopping experience. The quality of products is top-notch and the customer service is exceptional.',
      rating: 5,
    },
    {
      id: 2,
      name: 'Jane Smith',
      testimonial: 'I was blown away by the variety of products offered by Vestia. The website is easy to navigate and the checkout process is seamless.',
      rating: 5,
    },
    {
      id: 3,
      name: 'Bob Johnson',
      testimonial: 'Vestia has exceeded my expectations in every way. The prices are competitive, the shipping is fast, and the products are always in stock.',
      rating: 5,
    },
  ]);

  const handleNextSlide = () => {
    if (currentSlide < testimonials.length - 1) {
      setCurrentSlide(currentSlide + 1);
    } else {
      setCurrentSlide(0);
    }
  };

  const handlePrevSlide = () => {
    if (currentSlide > 0) {
      setCurrentSlide(currentSlide - 1);
    } else {
      setCurrentSlide(testimonials.length - 1);
    }
  };

  return (
    <div className="bg-zinc-600 p-10 md:p-20 lg:p-32 rounded-md shadow-none">
      <div className="flex flex-col justify-center items-center">
        <h2 className="text-3xl md:text-5xl lg:text-7xl font-bold text-zinc-200 mb-5 md:mb-10 lg:mb-20">What Our Customers Say</h2>
        <div className="w-full md:w-2/3 lg:w-1/2 xl:w-1/3 mx-auto">
          <div className="relative">
            <div className="flex justify-center items-center mb-10 md:mb-20">
              <button
                className="bg-zinc-700 hover:bg-zinc-800 text-zinc-200 p-2 md:p-4 lg:p-6 rounded-md mr-2 md:mr-4 lg:mr-6"
                onClick={handlePrevSlide}
              >
                <ArrowLeft size={20} className="text-zinc-200" />
              </button>
              <button
                className="bg-zinc-700 hover:bg-zinc-800 text-zinc-200 p-2 md:p-4 lg:p-6 rounded-md ml-2 md:ml-4 lg:ml-6"
                onClick={handleNextSlide}
              >
                <ArrowRight size={20} className="text-zinc-200" />
              </button>
            </div>
            <div className="bg-zinc-700 p-5 md:p-10 lg:p-20 rounded-md shadow-none">
              <p className="text-zinc-200 text-lg md:text-2xl lg:text-3xl font-bold mb-5 md:mb-10 lg:mb-20">{testimonials[currentSlide].testimonial}</p>
              <div className="flex justify-between items-center">
                <h3 className="text-zinc-200 text-lg md:text-2xl lg:text-3xl font-bold">{testimonials[currentSlide].name}</h3>
                <p className="text-zinc-400 text-lg md:text-2xl lg:text-3xl">{testimonials[currentSlide].rating}/5</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TestimonialCarousel;

